import './App.css';
import Title from './Components/Title';
import NavSideBar from './Components/NavSideBar';
import MainPage from './Components/MainPage';
import AboutPage from './Components/AboutPage';
import SkillsPage from './Components/SkillsPage';
import ProjectPage from './Components/ProjectPage';
import React, {useRef, useState, useEffect} from "react";
import ScrollAnimation from 'react-animate-on-scroll';
function App() {
  const animeLoop = true;
  const ref1 = useRef(null);
  const [width, setWindowWidth] = useState(0)
   useEffect(() => { 

     updateDimensions();

     window.addEventListener("resize", updateDimensions);
     return () => 
       window.removeEventListener("resize",updateDimensions);
    }, [])
    const updateDimensions = () => {
      const width = window.innerWidth
      setWindowWidth(width)
    }
  return (
    <div className="Main" id="mainpage">
        <NavSideBar refs={ref1} styl={{width: (width > 1000)?"250px":"0px",display: (width > 1000)?"block":"none"}} />
      <div className="Container" style={{width: (width > 1000)?"calc(100% - 250px)":"100%", left:(width>1000)?"250px":"0px"}}>
        <MainPage animeL={animeLoop} />
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={100} duration={0.7} animateOnce={animeLoop}>
          <Title name="A PROPOS" id="apropos" />
        </ScrollAnimation>
        <AboutPage animeL={animeLoop} />
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={110} duration={0.7} animateOnce={animeLoop}>
          <Title name="PROJETS" id="projets" />
        </ScrollAnimation>
        <ProjectPage />
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={120} duration={0.7} animateOnce={animeLoop}>
        <Title name="COMPETENCES" id="competences" />
        </ScrollAnimation>
        <SkillsPage />
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={130} duration={0.7} animateOnce={animeLoop}>
          <Title name="PARCOURS" id="parcours" />
        </ScrollAnimation>
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={140} duration={0.7} animateOnce={animeLoop}>
          <Title name="LANGUES" id="langues" />
        </ScrollAnimation>
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={150} duration={0.7} animateOnce={animeLoop}>
          <Title name="TELECHARGER CV" id="cv" />
        </ScrollAnimation>
        <ScrollAnimation animateIn='fadeInRight' offset={20} delay={160} duration={0.7} animateOnce={animeLoop}>
          <Title name="CONTACT" id="contact" />
        </ScrollAnimation>
      </div>
    </div>
  );
}

export default App;
